import{_ as e,o as d,c as o,ag as r}from"./chunks/framework.DAY4Zhxq.js";const u=JSON.parse('{"title":"Frontend Reference","description":"","frontmatter":{},"headers":[],"relativePath":"dev/frontend.md","filePath":"dev/frontend.md"}'),s={name:"dev/frontend.md"};function a(c,t,n,i,l,h){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="frontend-reference" tabindex="-1">Frontend Reference <a class="header-anchor" href="#frontend-reference" aria-label="Permalink to &quot;Frontend Reference&quot;">​</a></h1><p>The Vue 3 frontend lives in <code>src/</code>. It uses the Composition API exclusively and communicates with the Rust backend via <code>@tauri-apps/api/core</code> <code>invoke()</code> calls and <code>@tauri-apps/api/event</code> listeners.</p><h2 id="pinia-stores-src-stores" tabindex="-1">Pinia Stores (<code>src/stores/</code>) <a class="header-anchor" href="#pinia-stores-src-stores" aria-label="Permalink to &quot;Pinia Stores (`src/stores/`)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Store</th><th>File</th><th>Manages</th></tr></thead><tbody><tr><td><code>chat</code></td><td><code>chat.ts</code></td><td>Conversations, messages, streaming state, draft</td></tr><tr><td><code>models</code></td><td><code>models.ts</code></td><td>Local models, pull progress, model user data</td></tr><tr><td><code>hosts</code></td><td><code>hosts.ts</code></td><td>Host list, health status, active host</td></tr><tr><td><code>settings</code></td><td><code>settings.ts</code></td><td>KV settings, generation defaults</td></tr><tr><td><code>auth</code></td><td><code>auth.ts</code></td><td>Authentication state, sign-in flow</td></tr></tbody></table><h2 id="key-composables-src-composables" tabindex="-1">Key Composables (<code>src/composables/</code>) <a class="header-anchor" href="#key-composables-src-composables" aria-label="Permalink to &quot;Key Composables (`src/composables/`)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Composable</th><th>Purpose</th></tr></thead><tbody><tr><td><code>useStreaming.ts</code></td><td>Accumulates streaming tokens into reactive state</td></tr><tr><td><code>useStreamingEvents.ts</code></td><td>Registers Tauri event listeners for all <code>chat:*</code> events</td></tr><tr><td><code>useSendMessage.ts</code></td><td>Orchestrates message send flow (validate, invoke, stream)</td></tr><tr><td><code>useConversationLifecycle.ts</code></td><td>New conversation creation, switching, deletion</td></tr><tr><td><code>useAppOrchestration.ts</code></td><td>Top-level app startup and teardown</td></tr><tr><td><code>useDraftManager.ts</code></td><td>Per-conversation draft persistence (settings, input text)</td></tr><tr><td><code>useContextWindow.ts</code></td><td>Folder context attach/detach, token counting</td></tr><tr><td><code>useAttachments.ts</code></td><td>Image/file attachment handling</td></tr><tr><td><code>useAutoScroll.ts</code></td><td>Chat auto-scroll with manual override detection</td></tr><tr><td><code>useKeyboard.ts</code></td><td>Global keyboard shortcut registration</td></tr><tr><td><code>useTheme.ts</code></td><td>Dark/light mode toggle and persistence</td></tr><tr><td><code>useModelLibrary.ts</code></td><td>Ollama library search and tag fetching</td></tr></tbody></table><h2 id="tauri-event-catalog" tabindex="-1">Tauri Event Catalog <a class="header-anchor" href="#tauri-event-catalog" aria-label="Permalink to &quot;Tauri Event Catalog&quot;">​</a></h2><p>All events emitted from the Rust backend and listened to in the frontend:</p><table tabindex="0"><thead><tr><th>Event</th><th>Payload</th><th>Listener</th></tr></thead><tbody><tr><td><code>chat:token</code></td><td><code>{ conversation_id, content }</code></td><td><code>useStreamingEvents.ts</code></td></tr><tr><td><code>chat:thinking-start</code></td><td><code>{ conversation_id }</code></td><td><code>useStreamingEvents.ts</code></td></tr><tr><td><code>chat:thinking-token</code></td><td><code>{ conversation_id, content }</code></td><td><code>useStreamingEvents.ts</code></td></tr><tr><td><code>chat:thinking-end</code></td><td><code>{ conversation_id }</code></td><td><code>useStreamingEvents.ts</code></td></tr><tr><td><code>chat:done</code></td><td><code>{ conversation_id, tokens_per_sec? }</code></td><td><code>useStreamingEvents.ts</code></td></tr><tr><td><code>chat:error</code></td><td><code>{ conversation_id, error }</code></td><td><code>useStreamingEvents.ts</code></td></tr><tr><td><code>chat:tool-call</code></td><td><code>{ conversation_id, tool_name, arguments }</code></td><td><code>useStreamingEvents.ts</code></td></tr><tr><td><code>chat:tool-result</code></td><td><code>{ conversation_id, tool_name, result }</code></td><td><code>useStreamingEvents.ts</code></td></tr><tr><td><code>model:pull-progress</code></td><td><code>{ model, status, percent? }</code></td><td><code>stores/models.ts</code></td></tr><tr><td><code>model:pull-done</code></td><td><code>{ model }</code></td><td><code>stores/models.ts</code></td></tr><tr><td><code>host:status-change</code></td><td><code>{ host_id, status, latency_ms? }</code></td><td><code>stores/hosts.ts</code></td></tr></tbody></table><h2 id="markdown-pipeline-src-lib-markdown-ts" tabindex="-1">Markdown Pipeline (<code>src/lib/markdown.ts</code>) <a class="header-anchor" href="#markdown-pipeline-src-lib-markdown-ts" aria-label="Permalink to &quot;Markdown Pipeline (`src/lib/markdown.ts`)&quot;">​</a></h2><p>Messages are rendered through: <strong>markdown-it</strong> (CommonMark + GFM) → <strong>Shiki</strong> (syntax highlighting, async, preloaded after mount) → <strong>KaTeX</strong> (LaTeX math via <code>$...$</code> and <code>$$...$$</code>).</p><p>Shiki is preloaded asynchronously after first mount to avoid blocking first render.</p>',12)])])}const p=e(s,[["render",a]]);export{u as __pageData,p as default};
